import React, { useState, useEffect } from 'react';
import { useDropzone } from 'react-dropzone';
import { getClients, uploadFile, manualEntry, getUploads } from '../utils/api';
import toast from 'react-hot-toast';
import {
  Upload,
  FileText,
  Image,
  Table,
  CheckCircle,
  Clock,
  XCircle,
  Plus,
  Pencil
} from 'lucide-react';

const PLATFORMS = ['meta', 'google', 'linkedin', 'twitter', 'tiktok', 'other'];

const fileIcon = (type) => {
  if (type === 'image') return <Image size={14} />;
  if (type === 'pdf') return <FileText size={14} />;
  return <Table size={14} />;
};

const statusBadge = (status) => {
  const map = {
    completed: {
      label: 'Extracted',
      cls: 'badge-green',
      icon: <CheckCircle size={10} />
    },
    processing: {
      label: 'Processing',
      cls: 'badge-yellow',
      icon: <Clock size={10} />
    },
    pending: {
      label: 'Pending',
      cls: 'badge-gray',
      icon: <Clock size={10} />
    },
    failed: {
      label: 'Failed',
      cls: 'badge-red',
      icon: <XCircle size={10} />
    }
  };

  const s = map[status] || map.pending;

  return (
    <span className={`badge ${s.cls}`}>
      {s.icon} {s.label}
    </span>
  );
};

export default function UploadData() {
  const [clients, setClients] = useState([]);
  const [selectedClient, setSelectedClient] = useState('');
  const [platform, setPlatform] = useState('meta');
  const [dateStart, setDateStart] = useState('');
  const [dateEnd, setDateEnd] = useState('');
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [uploads, setUploads] = useState([]);
  const [mode, setMode] = useState('file');

  const [manualForm, setManualForm] = useState({
    spend: '',
    impressions: '',
    clicks: '',
    ctr: '',
    cpc: '',
    conversions: '',
    cpa: '',
    roas: '',
    revenue: '',
    campaignName: ''
  });

  useEffect(() => {
    getClients().then(setClients).catch(() => {});
  }, []);

  useEffect(() => {
    if (selectedClient) {
      getUploads(selectedClient).then(setUploads).catch(() => {});
    }
  }, [selectedClient]);

  const {
    getRootProps,
    getInputProps,
    isDragActive,
    acceptedFiles
  } = useDropzone({
    accept: {
      'text/csv': ['.csv'],
      'application/vnd.ms-excel': ['.xls'],
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': ['.xlsx'],
      'application/pdf': ['.pdf'],
      'image/png': ['.png'],
      'image/jpeg': ['.jpg', '.jpeg']
    },
    maxFiles: 1,
    maxSize: 50 * 1024 * 1024
  });

  const handleUpload = async () => {
    if (!selectedClient) {
      toast.error('Please select a client');
      return;
    }

    if (!acceptedFiles.length) {
      toast.error('Please select a file');
      return;
    }

    setUploading(true);
    setProgress(0);

    const fd = new FormData();

    fd.append('file', acceptedFiles[0]);
    fd.append('clientId', selectedClient);
    fd.append('platform', platform);

    if (dateStart) fd.append('dateRangeStart', dateStart);
    if (dateEnd) fd.append('dateRangeEnd', dateEnd);

    try {
      const result = await uploadFile(fd, setProgress);

      toast.success('File uploaded! Extraction in progress...');

      setUploads(prev => [
        {
          id: result.uploadId,
          file_name: acceptedFiles[0].name,
          file_type: result.fileType,
          extraction_status: 'processing',
          created_at: new Date().toISOString(),
          platform
        },
        ...prev
      ]);

      const poll = setInterval(async () => {
        const status = await getUploads(selectedClient);

        setUploads(status);

        if (status[0]?.extraction_status !== 'processing') {
          clearInterval(poll);

          if (status[0]?.extraction_status === 'completed') {
            toast.success('Data extraction complete!');
          } else if (status[0]?.extraction_status === 'failed') {
            toast.error('Extraction failed. Check file format.');
          }
        }
      }, 2000);

      setTimeout(() => clearInterval(poll), 30000);

    } catch (err) {
      toast.error(err.response?.data?.error || 'Upload failed');
    } finally {
      setUploading(false);
      setProgress(0);
    }
  };

  const setM = (k) => (e) =>
    setManualForm(f => ({
      ...f,
      [k]: e.target.value
    }));

  const handleManual = async () => {
    if (!selectedClient) {
      toast.error('Please select a client');
      return;
    }

    if (!dateStart) {
      toast.error('Please select a report month');
      return;
    }

    try {
      await manualEntry({
        clientId: selectedClient,
        platform,
        reportMonth: dateStart,
        campaignName: manualForm.campaignName || undefined,
        metrics: Object.fromEntries(
          Object.entries(manualForm)
            .filter(([k]) => k !== 'campaignName')
            .map(([k, v]) => [k, parseFloat(v) || 0])
        )
      });

      toast.success('Data saved!');

      setManualForm({
        spend: '',
        impressions: '',
        clicks: '',
        ctr: '',
        cpc: '',
        conversions: '',
        cpa: '',
        roas: '',
        revenue: '',
        campaignName: ''
      });

      if (selectedClient) {
        getUploads(selectedClient).then(setUploads);
      }

    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to save');
    }
  };

  return (
    <div className="fade-in">
      <div className="page-header">
        <div className="page-title">Upload Data</div>
        <div className="page-subtitle">
          Import ad performance data from files or enter manually
        </div>
      </div>

      <div className="grid grid-2" style={{ gap: 20, alignItems: 'start' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>

          <div className="card card-pad">
            <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 16 }}>
              Configuration
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>

              <div className="form-group">
                <label className="form-label">Client *</label>

                <select
                  className="form-select"
                  value={selectedClient}
                  onChange={e => setSelectedClient(e.target.value)}
                >
                  <option value="">Select client...</option>

                  {clients.map(c => (
                    <option key={c.id} value={c.id}>
                      {c.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Platform *</label>

                <select
                  className="form-select"
                  value={platform}
                  onChange={e => setPlatform(e.target.value)}
                >
                  {PLATFORMS.map(p => (
                    <option key={p} value={p}>
                      {p.charAt(0).toUpperCase() + p.slice(1)}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          <div className="card card-pad">
            <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 14 }}>
              Enter Metrics Manually
            </div>

            <div className="grid grid-2">

              {[
                { key: 'spend', label: 'Spend (₹)', ph: '150000' },
                { key: 'impressions', label: 'Impressions', ph: '50000' },
                { key: 'clicks', label: 'Clicks', ph: '1200' },
                { key: 'ctr', label: 'CTR (%)', ph: '2.4' },
                { key: 'cpc', label: 'CPC (₹)', ph: '12.50' },
                { key: 'conversions', label: 'Conversions', ph: '85' },
                { key: 'cpa', label: 'CPA (₹)', ph: '176.50' },
                { key: 'roas', label: 'ROAS', ph: '3.2' },
                { key: 'revenue', label: 'Revenue (₹)', ph: '480000' }
              ].map(({ key, label, ph }) => (
                <div key={key} className="form-group">
                  <label className="form-label">{label}</label>

                  <input
                    className="form-input"
                    type="number"
                    step="0.01"
                    placeholder={ph}
                    value={manualForm[key]}
                    onChange={setM(key)}
                  />
                </div>
              ))}

            </div>

            <button
              className="btn btn-primary"
              onClick={handleManual}
              disabled={!selectedClient}
              style={{ justifyContent: 'center', marginTop: 14 }}
            >
              <Plus size={14} />
              Save Data
            </button>
          </div>

        </div>
      </div>
    </div>
  );
}
